create or replace view public.enhancer_status as with base as (select er.id rule_id,er.month,er.store_id rule_store_id,e.store_id employee_store_id,er.brand,er.label,er.pct,er.flat_amount,er.metric,er.threshold,e.id employee_id,e.display_name rep,s.name dealer,coalesce(sum(case when d.make ilike er.make_pattern then coalesce(d.front_gross,0::numeric)*dp.split_pct else 0::numeric end),0::numeric) brand_front_gross,coalesce(sum(case when coalesce(d.make,''::text)<>''::text and coalesce(d.stock_number,''::text)<>''::text then coalesce(d.front_gross,0::numeric)*dp.split_pct else 0::numeric end),0::numeric) total_commissionable_gross,coalesce(sum(case when er.metric='new_units'::text and d.make ilike er.make_pattern and lower(coalesce(d.stock_type,''::text)) like '%new%'::text then dp.split_pct when er.metric='used_units'::text and d.make ilike er.make_pattern and lower(coalesce(d.stock_type,''::text)) not like '%new%'::text then dp.split_pct when er.metric='total_units'::text and d.make ilike er.make_pattern then dp.split_pct when er.metric='priority_units'::text and exists (select 1 from public.priority_stock ps where ps.month=er.month and ps.stock_number=d.stock_number and ps.store_id is not distinct from er.store_id) then dp.split_pct when er.metric='trades'::text and d.make ilike er.make_pattern then coalesce(d.trade_count,0::numeric)*dp.split_pct when er.metric='acquisitions'::text and coalesce(d.make,''::text)=''::text then dp.split_pct when er.metric='trades_acquisitions'::text then coalesce(d.trade_count,0::numeric)*dp.split_pct + case when coalesce(d.make,''::text)=''::text then dp.split_pct else 0::numeric end else 0::numeric end),0::numeric) metric_value from public.enhancer_rules er join public.employees e on er.store_id is null or e.store_id=er.store_id left join public.stores s on s.id=e.store_id left join public.deal_participants dp on dp.employee_id=e.id left join public.sales_deals d on d.id=dp.deal_id and date_trunc('month',d.contract_date)::date=er.month where er.metric<>'manual'::text group by er.id,er.month,er.store_id,e.store_id,er.brand,er.label,er.pct,er.flat_amount,er.metric,er.threshold,e.id,e.display_name,s.name) select rule_id,month,coalesce(rule_store_id,employee_store_id) store_id,brand,label,pct,flat_amount,metric,threshold,employee_id,rep,dealer,metric_value,brand_front_gross,metric_value>=threshold qualified,round(case when flat_amount is not null then flat_amount*metric_value else coalesce(pct,0::numeric)*total_commissionable_gross/100::numeric end,2) proposed_amount,total_commissionable_gross from base;